import Foundation

// Vendored third-party JS/CSS for the Phase C mobile client (see `embeddedPageHTML` in
// `MobileBridgeServer.swift`). MIT-licensed, unmodified content (trailing
// `//# sourceMappingURL=` comments stripped before encoding — the .map files aren't served,
// so leaving the reference in would cost the phone one dead-end fetch per load). Base64,
// not a raw Swift string: the minified xterm.js embeds literal C0 control bytes (mouse-
// tracking escape sequences like ESC `[M...`) that Swift's compiler rejects outright
// ("unprintable ASCII character found in source file") in any string literal, raw or not.
// Single Swift-string source of truth for the same reason `embeddedPageHTML` already is
// one: no separate asset file some other HTTP server has to host. To update, re-fetch from
// jsdelivr, strip the sourcemap comment, base64, and replace the literal wholesale.
#if canImport(Network)
enum MobileBridgeWebAssets {
    private static func decode(_ base64: String) -> String {
        // `.ignoreUnknownCharacters`: the vendored constants below are `base64`(1)'s default
        // 76-column-wrapped output — the embedded newlines aren't valid base64 alphabet, and
        // `Data(base64Encoded:)` fails the WHOLE decode (not just those characters) without
        // this option. Caught live: the served page silently degraded to this fallback comment
        // in place of all three assets — build-green had no way to catch it (see MEMORY.md
        // 2026-07-07 lesson: async/data-loading bugs need a real round-trip, not just a build).
        guard let data = Data(base64Encoded: base64, options: .ignoreUnknownCharacters) else {
            return "/* MobileBridgeWebAssets: base64 decode failed */"
        }
        return String(decoding: data, as: UTF8.self)
    }

    /// @xterm/xterm 5.5.0 — lib/xterm.js
    static let xtermJS = decode(xtermJSBase64)
    /// @xterm/xterm 5.5.0 — css/xterm.css
    static let xtermCSS = decode(xtermCSSBase64)
    /// @xterm/addon-fit 0.10.0 — lib/addon-fit.js
    static let addonFitJS = decode(addonFitJSBase64)

    private static let xtermJSBase64 = """


"""

    private static let xtermCSSBase64 = """


"""

    private static let addonFitJSBase64 = """


"""
}
#endif
